package examples.resources

import cats.effect.*
import io.circe.*
import io.circe.generic.semiauto.*
import mcp.protocol.Icon
import mcp.server.ResourceDef

/** Server configuration resource.
  *
  * This demonstrates a resource that returns structured JSON data.
  */
object ServerConfigResource {

  case class ServerConfig(
      name: String,
      version: String,
      environment: String
  ) derives Codec.AsObject

  // Config/settings gear icon
  // Original: <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>
  private val configIcon =
    "data:image/svg+xml;base64,"

  def apply[F[_]: Async]: ResourceDef[F, ServerConfig] =
    ResourceDef[F, ServerConfig](
      uri = "config://server.json",
      name = "Server Configuration",
      description = Some("Current server configuration"),
      mimeType = Some("application/json"),
      icons = Some(
        List(
          Icon(src = configIcon, mimeType = Some("image/svg+xml"), sizes = Some(List("any")))
        )
      ),
      handler = _ =>
        Async[F].pure(
          ServerConfig(
            name = "simple-server",
            version = "1.0.0",
            environment = "development"
          )
        )
    )
}
